SELECT "t19"."D_YEAR000" AS "PREV_YEAR", "t19"."D_YEAR01" AS "YEAR_VAL", "t19"."I_BRAND_ID01" AS "I_BRAND_ID", "t19"."I_CLASS_ID01" AS "I_CLASS_ID", "t19"."I_CATEGORY_ID01" AS "I_CATEGORY_ID", "t19"."I_MANUFACT_ID01" AS "I_MANUFACT_ID", "t19"."$f500" AS "PREV_YR_CNT", "t19"."$f51" AS "CURR_YR_CNT", "t19"."$f22" AS "SALES_CNT_DIFF", "t19"."$f23" AS "SALES_AMT_DIFF"
FROM (SELECT "t16"."D_YEAR0" AS "D_YEAR000", "t7"."D_YEAR0" AS "D_YEAR01", "t7"."I_BRAND_ID0" AS "I_BRAND_ID01", "t7"."I_CLASS_ID0" AS "I_CLASS_ID01", "t7"."I_CATEGORY_ID0" AS "I_CATEGORY_ID01", "t7"."I_MANUFACT_ID0" AS "I_MANUFACT_ID01", "t16"."$f5" AS "$f500", "t7"."$f5" AS "$f51", "t7"."$f5" - "t16"."$f5" AS "$f22", "t7"."$f6" - "t16"."$f6" AS "$f23"
FROM (SELECT "D_YEAR0", "I_BRAND_ID0", "I_CLASS_ID0", "I_CATEGORY_ID0", "I_MANUFACT_ID0", SUM("$f116") AS "$f5", SUM("$f117") AS "$f6"
FROM (SELECT *
FROM (SELECT "DATE_DIM"."D_YEAR" AS "D_YEAR0", "ITEM"."I_BRAND_ID" AS "I_BRAND_ID0", "ITEM"."I_CLASS_ID" AS "I_CLASS_ID0", "ITEM"."I_CATEGORY_ID" AS "I_CATEGORY_ID0", "ITEM"."I_MANUFACT_ID" AS "I_MANUFACT_ID0", "CATALOG_SALES"."CS_QUANTITY" - CASE WHEN "CATALOG_RETURNS"."CR_RETURN_QUANTITY" IS NOT NULL THEN CAST("CATALOG_RETURNS"."CR_RETURN_QUANTITY" AS INTEGER) ELSE 0 END AS "$f116", "CATALOG_SALES"."CS_EXT_SALES_PRICE" - CASE WHEN "CATALOG_RETURNS"."CR_RETURN_AMOUNT" IS NOT NULL THEN CAST("CATALOG_RETURNS"."CR_RETURN_AMOUNT" AS DECIMAL(7, 2)) ELSE 0.00 END AS "$f117"
FROM "tpcds"."CATALOG_SALES"
