INNER JOIN "tpcds"."DATE_DIM" ON "CATALOG_SALES"."CS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK"
LEFT JOIN "tpcds"."CATALOG_RETURNS" ON "CATALOG_SALES"."CS_ORDER_NUMBER" = "CATALOG_RETURNS"."CR_ORDER_NUMBER" AND "CATALOG_SALES"."CS_ITEM_SK" = "CATALOG_RETURNS"."CR_ITEM_SK"
WHERE "ITEM"."I_CATEGORY" = 'distmember(categories,61,1)'
UNION
SELECT "DATE_DIM0"."D_YEAR" AS "D_YEAR0", "ITEM0"."I_BRAND_ID" AS "I_BRAND_ID0", "ITEM0"."I_CLASS_ID" AS "I_CLASS_ID0", "ITEM0"."I_CATEGORY_ID" AS "I_CATEGORY_ID0", "ITEM0"."I_MANUFACT_ID" AS "I_MANUFACT_ID0", "STORE_SALES"."SS_QUANTITY" - CASE WHEN "STORE_RETURNS"."SR_RETURN_QUANTITY" IS NOT NULL THEN CAST("STORE_RETURNS"."SR_RETURN_QUANTITY" AS INTEGER) ELSE 0 END AS "$f98", "STORE_SALES"."SS_EXT_SALES_PRICE" - CASE WHEN "STORE_RETURNS"."SR_RETURN_AMT" IS NOT NULL THEN CAST("STORE_RETURNS"."SR_RETURN_AMT" AS DECIMAL(7, 2)) ELSE 0.00 END AS "$f99"
FROM "tpcds"."STORE_SALES"
INNER JOIN "tpcds"."ITEM" AS "ITEM0" ON "STORE_SALES"."SS_ITEM_SK" = "ITEM0"."I_ITEM_SK"
