SELECT "DATE_DIM1"."D_YEAR" AS "D_YEAR0", "ITEM1"."I_BRAND_ID" AS "I_BRAND_ID0", "ITEM1"."I_CLASS_ID" AS "I_CLASS_ID0", "ITEM1"."I_CATEGORY_ID" AS "I_CATEGORY_ID0", "ITEM1"."I_MANUFACT_ID" AS "I_MANUFACT_ID0", "WEB_SALES"."WS_QUANTITY" - CASE WHEN "WEB_RETURNS"."WR_RETURN_QUANTITY" IS NOT NULL THEN CAST("WEB_RETURNS"."WR_RETURN_QUANTITY" AS INTEGER) ELSE 0 END AS "$f113", "WEB_SALES"."WS_EXT_SALES_PRICE" - CASE WHEN "WEB_RETURNS"."WR_RETURN_AMT" IS NOT NULL THEN CAST("WEB_RETURNS"."WR_RETURN_AMT" AS DECIMAL(7, 2)) ELSE 0.00 END AS "$f114"
FROM "tpcds"."WEB_SALES"
