INNER JOIN "tpcds"."DATE_DIM" AS "DATE_DIM1" ON "WEB_SALES"."WS_SOLD_DATE_SK" = "DATE_DIM1"."D_DATE_SK"
LEFT JOIN "tpcds"."WEB_RETURNS" ON "WEB_SALES"."WS_ORDER_NUMBER" = "WEB_RETURNS"."WR_ORDER_NUMBER" AND "WEB_SALES"."WS_ITEM_SK" = "WEB_RETURNS"."WR_ITEM_SK"
WHERE "ITEM1"."I_CATEGORY" = 'distmember(categories,61,1)') AS "t6"
GROUP BY "D_YEAR0", "I_BRAND_ID0", "I_CLASS_ID0", "I_CATEGORY_ID0", "I_MANUFACT_ID0") AS "t7",
(SELECT "D_YEAR0", "I_BRAND_ID0", "I_CLASS_ID0", "I_CATEGORY_ID0", "I_MANUFACT_ID0", SUM("$f116") AS "$f5", SUM("$f117") AS "$f6"
FROM (SELECT *
FROM (SELECT "DATE_DIM2"."D_YEAR" AS "D_YEAR0", "ITEM2"."I_BRAND_ID" AS "I_BRAND_ID0", "ITEM2"."I_CLASS_ID" AS "I_CLASS_ID0", "ITEM2"."I_CATEGORY_ID" AS "I_CATEGORY_ID0", "ITEM2"."I_MANUFACT_ID" AS "I_MANUFACT_ID0", "CATALOG_SALES0"."CS_QUANTITY" - CASE WHEN "CATALOG_RETURNS0"."CR_RETURN_QUANTITY" IS NOT NULL THEN CAST("CATALOG_RETURNS0"."CR_RETURN_QUANTITY" AS INTEGER) ELSE 0 END AS "$f116", "CATALOG_SALES0"."CS_EXT_SALES_PRICE" - CASE WHEN "CATALOG_RETURNS0"."CR_RETURN_AMOUNT" IS NOT NULL THEN CAST("CATALOG_RETURNS0"."CR_RETURN_AMOUNT" AS DECIMAL(7, 2)) ELSE 0.00 END AS "$f117"
FROM "tpcds"."CATALOG_SALES" AS "CATALOG_SALES0"
INNER JOIN "tpcds"."ITEM" AS "ITEM2" ON "CATALOG_SALES0"."CS_ITEM_SK" = "ITEM2"."I_ITEM_SK"
INNER JOIN "tpcds"."DATE_DIM" AS "DATE_DIM2" ON "CATALOG_SALES0"."CS_SOLD_DATE_SK" = "DATE_DIM2"."D_DATE_SK"
LEFT JOIN "tpcds"."CATALOG_RETURNS" AS "CATALOG_RETURNS0" ON "CATALOG_SALES0"."CS_ORDER_NUMBER" = "CATALOG_RETURNS0"."CR_ORDER_NUMBER" AND "CATALOG_SALES0"."CS_ITEM_SK" = "CATALOG_RETURNS0"."CR_ITEM_SK"
WHERE "ITEM2"."I_CATEGORY" = 'distmember(categories,61,1)'
