SELECT "DATE_DIM3"."D_YEAR" AS "D_YEAR0", "ITEM3"."I_BRAND_ID" AS "I_BRAND_ID0", "ITEM3"."I_CLASS_ID" AS "I_CLASS_ID0", "ITEM3"."I_CATEGORY_ID" AS "I_CATEGORY_ID0", "ITEM3"."I_MANUFACT_ID" AS "I_MANUFACT_ID0", "STORE_SALES0"."SS_QUANTITY" - CASE WHEN "STORE_RETURNS0"."SR_RETURN_QUANTITY" IS NOT NULL THEN CAST("STORE_RETURNS0"."SR_RETURN_QUANTITY" AS INTEGER) ELSE 0 END AS "$f98", "STORE_SALES0"."SS_EXT_SALES_PRICE" - CASE WHEN "STORE_RETURNS0"."SR_RETURN_AMT" IS NOT NULL THEN CAST("STORE_RETURNS0"."SR_RETURN_AMT" AS DECIMAL(7, 2)) ELSE 0.00 END AS "$f99"
