INNER JOIN "tpcds"."ITEM" AS "ITEM3" ON "STORE_SALES0"."SS_ITEM_SK" = "ITEM3"."I_ITEM_SK"
INNER JOIN "tpcds"."DATE_DIM" AS "DATE_DIM3" ON "STORE_SALES0"."SS_SOLD_DATE_SK" = "DATE_DIM3"."D_DATE_SK"
