WHERE "ITEM4"."I_CATEGORY" = 'distmember(categories,61,1)') AS "t15"
GROUP BY "D_YEAR0", "I_BRAND_ID0", "I_CLASS_ID0", "I_CATEGORY_ID0", "I_MANUFACT_ID0") AS "t16"
WHERE "t7"."I_BRAND_ID0" = "t16"."I_BRAND_ID0" AND ("t7"."I_CLASS_ID0" = "t16"."I_CLASS_ID0" AND "t7"."I_CATEGORY_ID0" = "t16"."I_CATEGORY_ID0") AND ("t7"."I_MANUFACT_ID0" = "t16"."I_MANUFACT_ID0" AND "t7"."D_YEAR0" = 2002 AND ("t16"."D_YEAR0" = 2002 - 1 AND CAST("t7"."$f5" AS DECIMAL(17, 2)) / CAST("t16"."$f5" AS DECIMAL(17, 2)) < 0.900000))
